mapper.select:

WHERE r.gym_id = #{gymId}

  AND r.status = #{status}


  AND r.reason = #{reason}

ORDER BY r.created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM crm_re_registration r
 WHERE r.gym_id = #{gymId}

   AND r.status = #{status}


   AND r.reason = #{reason}

SELECT COUNT(*) > 0
  FROM crm_re_registration
 WHERE member_id = #{memberId}
   AND gym_id    = #{gymId}
   AND reason    = #{reason}
   AND status NOT IN ('success','failed')
